# Claude Zombies - Nacht der Untoten
#
# Modeled on the original Call of Duty: World at War map. Tight spawn
# bunker in the SW corner with all four boarded windows clustered around
# you, two debris-doors leading out (north "Help" stairs, east "Alley"),
# and a final gated back room holding the Pack-a-Punch.

NAME Nacht der Untoten

ATMOSPHERE
    fog       10 12 22  10 55     # near-black blue, soaks in over ~45 m
    sky_tint  255 255 255          # default neutral sky
    music     nacht_loop
END

SECTOR bunker  -32 -32  16 16  0
    # --- SW SPAWN BUNKER (x: -40..-25, z: -40..-25) ---

    SPAWN -32 -32
    SPAWN -30 -32
    SPAWN -32 -30
    SPAWN -34 -30

    # North wall (z=-25) with a $1000 stairs door at x=-32, 2 m wide
    WALL -40 -25  -25 -25  DOOR -32 2 1000  AS north_door

    # East wall (x=-25) with a $1000 alley door at z=-32, 2 m wide
    WALL -25 -40  -25 -25  DOOR -32 2 1000  AS east_door

    # Spawn-bunker cover (debris piled in the corners)
    OBSTACLE -33 -28  3 3
    OBSTACLE -27 -34  3 2 1
    OBSTACLE -38 -33  3 3 3

    # All four boarded windows are clustered around the spawn bunker,
    # gated by the door that leads to that side.
    WINDOW -35 -40  +z LOCKED_BY north_door
    WINDOW -28 -40  +z LOCKED_BY north_door
    WINDOW -40 -35  +x LOCKED_BY east_door
    WINDOW -40 -28  +x LOCKED_BY east_door

    # M1A1-style rifle right next to spawn on the south arena wall
    WALLBUY -32 -39.45  +z  RIFLE

    PERK -32 -28 SPEED
END

SECTOR main_hall  0 0  60 50  0
    # Everything between the bunker and the back room.

    OBSTACLE -10 -18  3 3
    OBSTACLE  10 -18  3 3
    OBSTACLE   0  -8  4 2
    OBSTACLE -22  -5  3 3
    OBSTACLE  22  -5  3 3
    OBSTACLE   0  10  6 3

    # SMG on the west arena wall, just outside the bunker
    WALLBUY -39.45 -10  +x  SMG
    # Shotgun on the east arena wall mid-map
    WALLBUY  39.45 -10  -x  SHOTGUN
    # Second rifle on the north arena wall, just outside the back-room door
    WALLBUY -10    39.45  -z  RIFLE

    PERK -15  -8 JUG
    PERK   8   0 DTAP

    # Classic Nacht "first random box" spot, out in the main hall
    MBOX 0 12

    # A line of sandbags forming cover in the centre of the hall
    PROP sandbag_stack -4 4 yaw 0
    PROP sandbag_stack  0 4 yaw 0
    PROP sandbag_stack  4 4 yaw 0
END

SECTOR back_room  27 27  26 26  0
    # --- BACK ROOM (NE corner, x: 15..40, z: 15..40) holding the PaP ---

    # South wall (z=15), full width
    WALL 16 15  40 15
    # West wall (x=15) with the $1500 entry door at z=25, 2 m wide
    WALL 15 15  15 40  DOOR 25 2 1500  AS backroom_door

    OBSTACLE 25 25  3 3
    OBSTACLE 32 22  3 3
    OBSTACLE 22 35  6 3 1

    # Ray gun gated in the back room
    WALLBUY 30 39.45  -z  RAYGUN

    PERK 30 30 STAMIN

    PAP  35 35
END
